const VALID_JOB_ACTIONS: JobAction[] = [
  "daily_brief", "full_report", "deep_dive", "new_ideas", "quick_check", "switch_production", "switch_testing",
];

// GET /api/admin/users/:userId/jobs — list all jobs for a user
